mapper.select:
select id, name, code
from station
where id = #{originStationId};

select id, name, code, city, province, is_hot
from station
where is_hot = 1;

select count(1) from (
select t.id from ticket t
left join line l on t.line_id = l.id
where l.start_station = #{stationId} or l.end_station = #{stationId}
union all
select ticket_id from stop_stations where station_id = #{stationId}
) as usage_count
